const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const countLiveNeighbors = (cell: Cell, liveSet: ReadonlySet<string>): number =>
  neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;

const survivesToNextGeneration = (cell: Cell, liveSet: ReadonlySet<string>): boolean => {
  const n = countLiveNeighbors(cell, liveSet);
  return liveSet.has(cellKey(cell)) ? n === 2 || n === 3 : n === 3;
};

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));

  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    for (const candidate of [cell, ...neighborsOf(cell)]) {
      candidates.set(cellKey(candidate), candidate);
    }
  }

  return [...candidates.values()].filter((cell) => survivesToNextGeneration(cell, liveSet));
}

